struct Node {
  int data;
  int left;
  int right;
  int height;
};

int Height(int index, Node arr[]) {
  if (index == -1) return 0;
  if (arr[index].height > 0) return arr[index].height;

  arr[index].height = 1 + std::max(Height(arr[index].left, arr), Height(arr[index].right, arr));
  return arr[index].height;
}

int Balance(int index, Node arr[]) {
  if (index == -1) return 0;
  return Height(arr[index].right, arr) - Height(arr[index].left, arr);
}

void UpdateHeight(int index, Node arr[]) {
  if (index == -1) return;

  arr[index].height = 1 + std::max(Height(arr[index].left, arr), Height(arr[index].right, arr));
}

int RightRotate(int y, Node arr[]) {
  int x = arr[y].left;
  int T2 = arr[x].right;

  arr[x].right = y;
  arr[y].left = T2;

  UpdateHeight(y, arr);
  UpdateHeight(x, arr);

  return x;
}

int LeftRotate(int x, Node arr[]) {
  int y = arr[x].right;
  int T2 = arr[y].left;

  arr[y].left = x;
  arr[x].right = T2;

  UpdateHeight(x, arr);
  UpdateHeight(y, arr);

  return y;
}

