Программа выдает ошибку «сегментации фолт» из-за обращения к недопустимой памяти. В данном коде есть несколько моментов, которые могут привести к этому:
- Индекс `index` в функции `print` является статической переменной, и увеличивается при каждом вызове `print`. При последующих вызовах `print`, начальное значение индекса продолжит увеличиваться, и это может привести к выходу за пределы массива нод, или вывод некорректных индексов.
- Входные данные предполагают, что индексы детей начинаются с `1`, `0` означает отсутствие ребенка, но в коде они изменяются на `-1` для `left` и `right`, и следует быть очень осторожным, чтобы не обратиться к массиву `arr` с недействительным индексом.

Если исправить код так, чтобы он корректно работал с индексами и надежно выводил дерево, результат будет выглядеть примерно так:

```cpp
#include <iostream>
#include <algorithm>

struct Node {
  int data;
  int left;      // these are the 1-based input indices as provided
  int right;     // these are the 1-based input indices as provided
  int height;
};

int Height(int index, Node arr[]) {
  if (index <= 0) return 0;  // modified to handle 1-based indices instead of -1
  index--;  // adjust for 0-based indexing within the function
  if (arr[index].height > 0) return arr[index].height;

  arr[index].height = 1 + std::max(Height(arr[index].left, arr), Height(arr[index].right, arr));
  return arr[index].height;
}

int Balance(int index, Node arr[]) {
  if (index <= 0) return 0;  // modified to handle 1-based indices
  index--;  // adjust for 0-based indexing within the function
  return Height(arr[index].right, arr) - Height(arr[index].left, arr);
}

void UpdateHeight(int index, Node arr[]) {
  if (index <= 0) return;  // modified to handle 1-based indices
  index--;  // adjust for 0-based indexing within the function

  arr[index].height = 1 + std::max(Height(arr[index].left, arr), Height(arr[index].right, arr));
}

int RightRotate(int y, Node arr[]) {
  y--;  // adjust for 0-based indexing
  int x = arr[y].left - 1;
  int T2 = arr[x].right;

  arr[x].right = y + 1;  // revert to 1-based index after internal processing
  arr[y].left = T2;

  UpdateHeight(y + 1, arr);
  UpdateHeight(x + 1, arr);

  return x + 1;  // return as 1-based index for internal processing
}

int LeftRotate(int x, Node arr[]) {
  x--;  // adjust for 0-based indexing
  int y = arr[x].right - 1;
  int T2 = arr[y].left;

  arr[y].left = x + 1;  // revert to 1-based index after internal processing
  arr[x].right = T2;

  UpdateHeight(x + 1, arr);
  UpdateHeight(y + 1, arr);

  return y + 1;  // return as 1-based index for internal processing
}

void print(int root, Node arr[], int &index) {
  if (root <= 0) return;
  root--;  // adjust for 0-based indexing
  if (arr[root].left > 0) {
    std::cout << arr[root].data << ' ';
    std::cout << arr[root].left << ' ';
    std::cout << "0\n";
    print(arr[root].left, arr, ++index);  // Need to pass index by reference
  }
  if (arr[root].right > 0) {
    std::cout << arr[root].data << ' ';
    std::cout << "0" << ' ';
    std::cout << arr[root].right << '\n';
    print(arr[root].right, arr, ++index);  // Need to pass index by reference
  }
}

int main() {
  int n;
  std::cin >> n;

  Node arr[n];
  for (int i = 0; i < n; ++i) {
    std::cin >> arr[i].data;
    std::cin >> arr[i].left >> arr[i].right;
    arr[i].height = 0;
  }

  for (int i = 0; i < n; ++i) {
    Height(i + 1, arr);  // pass 1-based index for root
  }

  int root = 1;  // start with 1-based index for root
  if (Balance(arr[root].right, arr) < 0) {
    arr[root].right = RightRotate(arr[root].right, arr);
  }

  root = LeftRotate(root, arr);

  std::cout << n << std::endl;
  int index = 1;  // Initialize index for proper printing
  print(root, arr, index);  // Pass index by reference

  return 0;
}

```
Обратите внимание, что я убрал статическую переменную `index` из функции `print` и передаю ее в функции как аргумент, чтобы избежать проблем с индексацией между вызовами.
