#include <iostream>
#include <string>

struct Node {
  std::string name;
  Node* left = nullptr;
  Node* right = nullptr;
  int height = 1;

  Node(const std::string& name) : name(name) {}
};

int height(Node* root) {
  if (root == nullptr) return 0;
  return root->height;
}

int Balance(Node* root) {
  if (root == nullptr) return 0;
  return height(root->left) - height(root->right);
}

Node* RightRotation(Node* y) {
  Node* x = y->left;
  Node* T2 = x->right;

  x->right = y;
  y->left = T2;

  y->height = std::max(height(y->left), height(y->right)) + 1;
  x->height = std::max(height(x->left), height(x->right)) + 1;

  return x;
}

Node* LeftRotation(Node* x) {
  Node* y = x->right;
  Node* T2 = y->left;

  y->left = x;
  x->right = T2;

  x->height = std::max(height(x->left), height(x->right)) + 1;
  y->height = std::max(height(y->left), height(y->right)) + 1;

  return y;
}

void Insert(Node*& root, const std::string& name, int& free_memory) {
  if (!root) {
    root = new Node(name);
    return;
  }

  if (name < root->name) {
    Insert(root->left, name, free_memory);
  } else if (name > root->name) {
    Insert(root->right, name, free_memory);
  } else {
    free_memory += name.length();
  }

  root->height = 1 + std::max(height(root->left), height(root->right));

  int balance = Balance(root);

  if (balance > 1 && name < root->left->name) {
    root = RightRotation(root);
  } else if (balance < -1 && name > root->right->name) {
    root = LeftRotation(root);
  } else if (balance > 1 && name > root->left->name) {
    root->left = LeftRotation(root->left);
    root = RightRotation(root);
  } else if (balance < -1 && name < root->right->name) {
    root->right = RightRotation(root->right);
    root = LeftRotation(root);
  }
}

int main() {
  int n;
  std::cin >> n;
  int free_memory = 0;
  Node* root = nullptr;
  for (int i = 0; i < n; ++j) {
    std::string name;
    std::cin >> name;
    Insert(root, name, free_memory);
  }
  std::cout << free_memory;
}


